#include<cstdio>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
typedef long long Ull;
const int Mod=1e9+7;
inline int Min(int x,int y){return x<y?x:y;}
inline int Max(int x,int y){return x>y?x:y;}
const int N=1e6+10;char s[N];Ull sv[N],sum[N];
inline Ull qpow(Ull a,int b){Ull res=1;while(b){b&1?res=res*a:0;a=a*a;b=b>>1;}return res;}
inline void Init(int n){sv[0]=1;rep(1,n,i)sv[i]=sv[i-1]*29%Mod;}
inline bool qry(int l1,int r1,int l2,int r2)
{
    if((r1-(--l1))^(r2-(--l2)))return 0;
    return ((sum[r1]-sum[l1]*sv[r1-l1])%Mod+Mod)%Mod==((sum[r2]-sum[l2]*sv[r2-l2])%Mod+Mod)%Mod;
}
int main()
{
    int n;scanf("%d%s",&n,s+1);Init(n);int L=n>>1;
    rep(1,n,i)sum[i]=(sum[i-1]*29+(s[i]-'a'))%Mod;
    int ans=0,cur=0;for(int i=L;i;cur=Min(cur+2,L-(--i)))
    {
        if(qry(1,i,n-i+1,n))
        {
            while(cur&&!qry(i+1,i+cur,n-i-cur+1,n-i))--cur;
            ans=Max(ans,i+cur);
        }
    }
    printf("%d\n",ans);return 0;
}
